// DeleteInventoryItem is the resolver for the deleteInventoryItem field.
// MutationEventHook detects the soft delete automatically.
func (r *mutationResolver) DeleteInventoryItem(ctx context.Context, id uuid.UUID) (*model.InventoryItemDeletePayload, error) {
	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	var resp model.InventoryItemDeletePayload
	req := request.ForContext(ctx)

	repositoryMap, err := r.stock.GetRepositoriesDetails(ctx, tx)
	if err != nil {
		return nil, err
	}

	var warehouseRepoIDs []uuid.UUID
	for _, v := range repositoryMap {
		if v.ParentID == uuid.Nil && !v.VirtualRepo {
			warehouseRepoIDs = append(warehouseRepoIDs, v.ID)
		}
	}

	if len(warehouseRepoIDs) > 0 {
		stockMap, err := r.stock.GetCurrentRepositoriesStock(ctx, tx, warehouseRepoIDs)
		if err != nil {
			return nil, fmt.Errorf("failed to query stock table: %w", err)
		}

		for _, itemStocks := range stockMap {
			if record, ok := itemStocks[id]; ok {
				if record.Quantity > 0 {
					return nil, fmt.Errorf("unable to remove item as long as it is in stock")
				}
				if record.IncomingStock > 0 {
					return nil, fmt.Errorf("unable to remove item as long as there are expected items in stock")
				}
				if record.OutgoingStock > 0 {
					return nil, fmt.Errorf("unable to remove item as long as there are reserved items in stock")
				}
			}
		}
	}

	_, err = tx.Item.
		UpdateOneID(id).
		SetDeletedAt(time.Now().UTC()).
		SetDeletedBy(req.User().ID).
		Save(ctx)
	if err != nil {
		return nil, err
	}

	resp.DeletedID = &id
	resp.Workflows = make([]*model.TemporalWorkflow, 0)

	return &resp, nil
}

