// MutationEventHook detects the soft delete automatically.
func (r *mutationResolver) DeleteInventoryRepository(ctx context.Context, id uuid.UUID) (*model.InventoryRepositoryDeletePayload, error) {
	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	var resp model.InventoryRepositoryDeletePayload
	req := request.ForContext(ctx)

	stockMap, err := r.stock.GetCurrentRepositoriesStock(ctx, tx, []uuid.UUID{id})
	if err != nil {
		return nil, fmt.Errorf("failed to query stock table: %w", err)
	}

	for _, record := range stockMap[id] {
		if record.Quantity > 0 {
			return nil, fmt.Errorf("unable to remove repository as long as there are items in stock")
		}
		if record.IncomingStock > 0 {
			return nil, fmt.Errorf("unable to remove repository as long as there are expected items in stock")
		}
		if record.OutgoingStock > 0 {
			return nil, fmt.Errorf("unable to remove repository as long as there are reserved items in stock")
		}
	}

	childList, err := tx.Repository.
		Query().
		Where(repository.ParentIDEQ(id)).
		Where(repository.TenantID(req.MutationTenantID())).
		AllPages(ctx, mixin.Limit)
	if err != nil {
		return nil, err
	}

	if len(childList) > 0 {
		return nil, fmt.Errorf("unable to remove repository as long as it has children")
	}

	_, err = tx.Repository.
		UpdateOneID(id).
		SetDeletedAt(time.Now().UTC()).
		SetDeletedBy(req.User().ID).
		Save(ctx)
	if err != nil {
		return nil, err
	}

	resp.DeletedID = &id
	resp.Workflows = make([]*model.TemporalWorkflow, 0)

	return &resp, nil
}

