// DeleteInventoryStock is the resolver for the deleteInventoryStock field.
// MutationEventHook captures the mutation automatically.
func (r *mutationResolver) DeleteInventoryStock(ctx context.Context, input model.ClearVirtualStockInput) (*model.RepositoryDeletePayload, error) {
	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	req := request.ForContext(ctx)

	repo, err := tx.Repository.Get(ctx, input.RepositoryID)
	if err != nil {
		return nil, err
	}

	if !repo.VirtualRepo {
		return nil, errors.New("items can only be deleted from virtual repositories")
	}

	where := predicate.Repository(func(s *sql.Selector) {
		s.Where(sql.EQ(repository.FieldParentID, repo.ID))
	})

	childReposIDList, err := tx.Repository.Query().Where(where).AllPages(ctx, mixin.Limit)
	if err != nil {
		return nil, err
	}

	repositoryIDList := make([]uuid.UUID, 0, len(childReposIDList)+2)
	for _, v := range childReposIDList {
		repositoryIDList = append(repositoryIDList, v.ID)
	}

	repositoryIDList = append(repositoryIDList, repo.ID)
	if repo.ParentID != uuid.Nil {
		repositoryIDList = append(repositoryIDList, repo.ParentID)
	}

	stockMap := map[uuid.UUID]map[uuid.UUID]ent.Stock{}
	if len(repositoryIDList) > 0 {
		stockMap, err = r.stock.GetCurrentRepositoriesStock(ctx, tx, repositoryIDList)
		if err != nil {
			return nil, err
		}
	}

	itemsToDelete := make([]uuid.UUID, 0)
	if input.ItemID != nil {
		itemsToDelete = append(itemsToDelete, *input.ItemID)
	} else {
		for _, v := range stockMap[repo.ID] {
			itemsToDelete = append(itemsToDelete, v.ItemID)
		}
	}

	stocksToCreate := []*ent.StockCreate{}
	transactionsToCreate := []*ent.TransactionCreate{}
	for _, v := range itemsToDelete {
		for _, c := range childReposIDList {
			if stockMap[c.ID][v].Quantity != 0 {
				stocksToCreate = append(
					stocksToCreate,
					tx.Stock.
						Create().
						SetItemID(v).
						SetTenantID(req.MutationTenantID()).
						SetRepositoryID(c.ID).
						SetQuantity(0).
						SetCreatedBy(req.User().ID).
						SetVersion(stockMap[c.ID][v].Version+1),
				)
				transactionsToCreate = append(
					transactionsToCreate,
					tx.Transaction.
						Create().
						SetItemID(v).
						SetTenantID(req.MutationTenantID()).
						SetRepositoryID(c.ID).
						SetType(transaction.TypeOut).
						SetQuantity(stockMap[repo.ID][v].Quantity).
						SetCreatedBy(req.User().ID),
				)
			}
		}

		if stockMap[repo.ID][v].Quantity != 0 {
			stocksToCreate = append(
				stocksToCreate,
				tx.Stock.
					Create().
					SetItemID(v).
					SetTenantID(req.MutationTenantID()).
					SetRepositoryID(repo.ID).
					SetQuantity(0).
					SetCreatedBy(req.User().ID).
					SetVersion(stockMap[repo.ID][v].Version+1),
			)
			transactionsToCreate = append(
				transactionsToCreate,
				tx.Transaction.
					Create().
					SetItemID(v).
					SetTenantID(req.MutationTenantID()).
					SetRepositoryID(repo.ID).
					SetType(transaction.TypeOut).
					SetQuantity(stockMap[repo.ID][v].Quantity).
					SetCreatedBy(req.User().ID),
			)
		}

		if repo.ParentID != uuid.Nil && stockMap[repo.ID][v].Quantity != 0 && stockMap[repo.ParentID][v].Quantity != 0 {
			stocksToCreate = append(
				stocksToCreate,
				tx.Stock.
					Create().
					SetItemID(v).
					SetTenantID(req.MutationTenantID()).
					SetRepositoryID(repo.ParentID).
					SetQuantity(stockMap[repo.ParentID][v].Quantity-stockMap[repo.ID][v].Quantity).
					SetCreatedBy(req.User().ID).
					SetVersion(stockMap[repo.ParentID][v].Version+1),
			)
			transactionsToCreate = append(
				transactionsToCreate,
				tx.Transaction.
					Create().
					SetItemID(v).
					SetTenantID(req.MutationTenantID()).
					SetRepositoryID(repo.ParentID).
					SetType(transaction.TypeOut).
					SetQuantity(stockMap[repo.ID][v].Quantity).
					SetCreatedBy(req.User().ID),
			)
		}
	}
	_, err = tx.Stock.CreateBulk(stocksToCreate...).Save(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed inserting stocks: %w", err)
	}

	_, err = tx.Transaction.CreateBulk(transactionsToCreate...).Save(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed inserting transactions: %w", err)
	}

	deletedID := input.RepositoryID
	if input.ItemID != nil {
		deletedID = *input.ItemID
	}

	return &model.RepositoryDeletePayload{DeletedID: &deletedID}, nil
}

// RebuildInventoryStock is the resolver for the rebuildInventoryStock field.
// Requires admin role to execute.
func (r *mutationResolver) RebuildInventoryStock(ctx context.Context) (*model.RebuildStockOutput, error) {
	req := request.ForContext(ctx)

	if !req.User().HasRole(authn.ROLE_ADMIN, req.MutationTenantID()) {
		return nil, fmt.Errorf("%w: admin role required for rebuildInventoryStock", authn.ErrUnauthorized)
	}

	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	// The rebuild replays every movement, writing one stock row per event.
	// Emitting an outbox event per replayed row would flood the outbox and can
	// OOM the publisher draining the backlog, so suppress event creation by
	// default for this mutation. A caller can opt back into normal event
	// emission by explicitly requesting sync updates (X-Pyck-Feature:
	// syncupdates); all other mutations keep the normal sync behavior.
	rebuildCtx := ctx
	if !feature.HasFeature(ctx, feature.FEATURE_SYNC_UPDATES) {
		rebuildCtx = feature.Context(ctx, feature.FEATURE_SUPPRESS_EVENTS)
	}

	if err := r.stock.RebuildStockTable(rebuildCtx, tx, req.MutationTenantID()); err != nil {
		return nil, err
	}

	return &model.RebuildStockOutput{Success: true}, nil
}

// CreateInventoryItemSet is the resolver for the createInventoryItemSet field.
// MutationEventHook captures the mutation automatically.
func (r *mutationResolver) CreateInventoryItemSet(ctx context.Context, input ent.CreateInventoryItemSetInput) (*model.InventoryItemSetOutput, error) {
	dataType, err := r.validator.ValidateDataTypeInput(ctx, true, input.Data, input.DataTypeID, input.DataTypeSlug)
	if err != nil {
		return nil, err
	}

	mixin.PatchDataTypeIdSlugInput(&input, dataType)

	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	var resp model.InventoryItemSetOutput
	req := request.ForContext(ctx)

	items, err := tx.Item.Query().
		Where(entitem.TenantID(req.MutationTenantID())).
		Where(entitem.IDIn(input.ItemIDs...)).
		AllPages(ctx, mixin.Limit)
	if err != nil {
		return nil, err
	}

	if len(items) != len(input.ItemIDs) {
		return nil, errors.New("invalid itemIDs")
	}

	itemIds := make(map[uuid.UUID]struct{})
	for _, item := range items {
		itemIds[item.ID] = struct{}{}
	}

	for _, itemID := range input.ItemIDs {
		_, ok := itemIds[itemID]
		if !ok {
			return nil, fmt.Errorf("item with ID %s not found", itemID)
		}
	}

	itemSet, err := tx.ItemSet.
		Create().
		SetInput(input).
		Save(ctx)
	if err != nil {
		return nil, err
	}

	if err = r.validator.ValidateInputDataUniqueness(ctx, tx, validator.UniquenessValidationParams{
		Input:     input.Data,
		DataType:  dataType,
		TableName: itemset.Table,
		FieldName: itemset.FieldData,
		DbDriver:  core.Config.DbDriver,
	}); err != nil {
		return nil, err
	}

	resp.InventoryItemSet = itemSet
	resp.Workflows = make([]*model.TemporalWorkflow, 0)

	return &resp, nil
}

